// End-to-end smoke for the image-carrier deblur pipeline.
//
// The test manufactures a known blur (σ=2 Gaussian PSF, FFT-circular convolution),
// runs the orchestrator, and asserts ΔPSNR vs the original image. ΔPSNR is the
// load-bearing measurement; the BuleyProjection score is a secondary contract
// (must stay under TOWER_CEILINGS.hexon).
//
// Floors picked to be conservative for Wiener with a known PSF on band-limited
// fixtures: 6 dB on the 256 image, 4 dB on the 512 image. The 512 floor is
// looser because the same σ=2 PSF covers proportionally less of the image.
// If either fails, the FFT layout, PSF placement, or colourspace handling is
// almost certainly wrong (see Risks in the plan file).

import { beforeAll, describe, expect, it } from 'vitest';
import { dirname, join, resolve } from 'path';
import { fileURLToPath } from 'url';

import { ensureSsdPngs } from './helpers/deblur-fixtures';
import { decodeLuminance } from '../src/image-decode';
import { gaussianPSF, applyPSF } from '../src/image-psf';
import { psnr } from '../src/image-quality';
import { deblurImageCarrier } from '../src/image-carrier-deblur';
import { TOWER_CEILINGS } from '../src/spectral-noise-monitor';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
// __dirname = .../distributed-inference-host/__tests__
//   ..       = .../distributed-inference-host
//   ../..    = .../gnosis
//   ../../.. = .../open-source
// ../../../.. = repo root
const REPO_ROOT = resolve(__dirname, '../../../..');
const FIXTURE_256 = join(REPO_ROOT, '.qa-artifacts/img-ssd-256.png');
const FIXTURE_512 = join(REPO_ROOT, '.qa-artifacts/img-ssd-512.png');

async function runSmoke(
  path: string,
  expectedSize: number,
  minDelta: number,
): Promise<void> {
  const { plane, width, height } = await decodeLuminance(path);
  expect(width).toBe(expectedSize);
  expect(height).toBe(expectedSize);

  const psf = gaussianPSF(2, 11);
  const blurred = applyPSF({
    plane, w: width, h: height,
    psf, psfW: 11, psfH: 11,
  });

  const result = deblurImageCarrier({
    input: {
      data: blurred,
      width,
      height,
      channels: 1,
      sampleRange: 'unit',
    },
    psf,
    psfW: 11,
    psfH: 11,
    pipelineConfig: { patchSize: 16 },
  });

  const psnrBlurred = psnr(plane, blurred);
  const psnrRecovered = psnr(plane, result.recovered);
  const delta = psnrRecovered - psnrBlurred;

  // Inspector output — Taylor reads this to learn smoke state.
  // eslint-disable-next-line no-console
  console.log(
    `[deblur-smoke ${expectedSize}x${expectedSize}] ` +
      `blurred=${psnrBlurred.toFixed(2)} dB  ` +
      `recovered=${psnrRecovered.toFixed(2)} dB  ` +
      `Δ=${delta.toFixed(2)} dB  ` +
      `face=${result.perStep[0]!.face}  reason=${result.perStep[0]!.reason}  ` +
      `score=${result.carrierBuley.score}`,
  );

  expect(delta).toBeGreaterThanOrEqual(minDelta);
  expect(result.carrierBuley.score).toBeLessThanOrEqual(TOWER_CEILINGS.hexon);
  expect(result.iterations).toBe(1);
  expect(result.perStep).toHaveLength(1);
}

describe('deblurImageCarrier smoke (Wiener, σ=2 PSF, FFT-circular)', () => {
  beforeAll(async () => {
    await ensureSsdPngs();
  });

  it('recovers ≥ 6 dB PSNR on img-ssd-256.png', async () => {
    await runSmoke(FIXTURE_256, 256, 6);
  }, 60_000);

  it('recovers ≥ 4 dB PSNR on img-ssd-512.png', async () => {
    await runSmoke(FIXTURE_512, 512, 4);
  }, 120_000);
});
